BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?body WHERE {
  ?elem vocab:NamedElement_name "Alignment and Phasing System (APS)" .
  OPTIONAL { ?elem vocab:Comment_body ?body }
}
LIMIT 10

